from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    if not tasks:
        return

    current_task = asyncio.current_task()
    next_index = 0
    running: set[asyncio.Task[None]] = set()
    first_error: BaseException | None = None

    def cancellation_requested() -> bool:
        return current_task is not None and current_task.cancelling() > 0

    def start_next() -> None:
        nonlocal next_index, first_error

        if next_index >= len(tasks) or first_error is not None:
            return

        try:
            task = asyncio.create_task(tasks[next_index]())
        except BaseException as exc:  # noqa: BLE001
            first_error = exc
            return

        next_index += 1
        running.add(task)

    for _ in range(min(max_concurrent, len(tasks))):
        if cancellation_requested():
            break
        start_next()
        if first_error is not None:
            break

    try:
        while running:
            done, _ = await asyncio.wait(
                running,
                return_when=asyncio.FIRST_COMPLETED,
            )
            running.difference_update(done)

            for task in done:
                try:
                    task.result()
                except BaseException as exc:  # noqa: BLE001
                    if first_error is None:
                        first_error = exc

            if first_error is None and not cancellation_requested():
                while len(running) < max_concurrent:
                    if cancellation_requested():
                        break
                    start_next()
                    if first_error is not None or next_index >= len(tasks):
                        break
    except asyncio.CancelledError:
        if running:
            await asyncio.shield(
                asyncio.gather(*running, return_exceptions=True),
            )
        raise

    if running:
        await asyncio.gather(*running, return_exceptions=True)

    if first_error is not None:
        raise first_error
